def process_transactions(accounts, transactions):
    """
    Processes financial transactions and updates account balances.

    :param accounts: A dictionary where keys are account IDs and values are the current balance.
    :param transactions: A list of transactions, each represented as a dictionary with 'account_id',
                         'amount', and 'type' ('credit' or 'debit').
    :return: Updated dictionary of account balances.
    """
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        trans_type = transaction['type'].lower()

        if account_id in accounts:
            if trans_type == 'credit':
                accounts[account_id] += amount
            elif trans_type == 'debit':
                accounts[account_id] -= amount
            else:
                raise ValueError(f"Invalid transaction type: {trans_type}")
        else:
            raise ValueError(f"Account ID {account_id} not found")

    return accounts

